import{_ as e,o as a,c as r,a2 as l}from"./chunks/framework.D46keoNO.js";const p=JSON.parse('{"title":"翻译服务","description":"","frontmatter":{},"headers":[],"relativePath":"guide/services.md","filePath":"guide/services.md","lastUpdated":1782819416000}'),i={name:"guide/services.md"};function o(n,t,d,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="翻译服务" tabindex="-1">翻译服务 <a class="header-anchor" href="#翻译服务" aria-label="Permalink to &quot;翻译服务&quot;">​</a></h1><h2 id="服务列表" tabindex="-1">服务列表 <a class="header-anchor" href="#服务列表" aria-label="Permalink to &quot;服务列表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服务</th><th>认证方式</th><th>费用</th><th>说明</th></tr></thead><tbody><tr><td>VS Code Copilot</td><td>零配置</td><td>需要 Copilot 订阅</td><td>推荐，无需额外配置</td></tr><tr><td>ChatGPT / OpenAI</td><td>API Key</td><td>按量付费</td><td>需要 OpenAI API Key</td></tr><tr><td>谷歌翻译</td><td>免费（有限制）</td><td>免费</td><td>无需配置，但有调用限制</td></tr><tr><td>Bing / Azure Translator</td><td>API Key</td><td>按量付费</td><td>需要 Azure 账号</td></tr><tr><td>DeepLX</td><td>本地部署</td><td>免费</td><td>需要本地部署服务</td></tr><tr><td>百度翻译</td><td>APP_ID + Key</td><td>按量付费</td><td>需要百度翻译开放平台账号</td></tr><tr><td>腾讯翻译君</td><td>SecretId + SecretKey</td><td>按量付费</td><td>需要腾讯云账号</td></tr></tbody></table><h2 id="api-获取方式" tabindex="-1">API 获取方式 <a class="header-anchor" href="#api-获取方式" aria-label="Permalink to &quot;API 获取方式&quot;">​</a></h2><h3 id="openai" tabindex="-1">OpenAI <a class="header-anchor" href="#openai" aria-label="Permalink to &quot;OpenAI&quot;">​</a></h3><ol><li>访问 <a href="https://platform.openai.com/" target="_blank" rel="noreferrer">OpenAI Platform</a></li><li>注册/登录账号</li><li>进入 <a href="https://platform.openai.com/api-keys" target="_blank" rel="noreferrer">API Keys 页面</a></li><li>点击 &quot;Create new secret key&quot;</li><li>复制生成的 API Key（格式：<code>sk-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</code>）</li></ol><h3 id="百度翻译" tabindex="-1">百度翻译 <a class="header-anchor" href="#百度翻译" aria-label="Permalink to &quot;百度翻译&quot;">​</a></h3><ol><li>访问 <a href="https://fanyi-api.baidu.com/" target="_blank" rel="noreferrer">百度翻译开放平台</a></li><li>注册/登录账号</li><li>进入 <a href="https://fanyi-api.baidu.com/aitrans" target="_blank" rel="noreferrer">控制台</a></li><li>开通通用翻译 API 服务</li><li>获取 APP_ID 和 Secret Key</li></ol><h3 id="腾讯翻译君" tabindex="-1">腾讯翻译君 <a class="header-anchor" href="#腾讯翻译君" aria-label="Permalink to &quot;腾讯翻译君&quot;">​</a></h3><ol><li>访问 <a href="https://console.cloud.tencent.com/" target="_blank" rel="noreferrer">腾讯云</a></li><li>注册/登录账号</li><li>开通 <a href="https://console.cloud.tencent.com/tmt" target="_blank" rel="noreferrer">机器翻译</a> 服务</li><li>进入 <a href="https://console.cloud.tencent.com/cam/capi" target="_blank" rel="noreferrer">API 密钥管理</a></li><li>获取 SecretId 和 SecretKey</li></ol><h3 id="bing-azure-translator" tabindex="-1">Bing / Azure Translator <a class="header-anchor" href="#bing-azure-translator" aria-label="Permalink to &quot;Bing / Azure Translator&quot;">​</a></h3><ol><li>访问 <a href="https://portal.azure.com/" target="_blank" rel="noreferrer">Azure Portal</a></li><li>注册/登录账号</li><li>创建 <a href="https://portal.azure.com/#create/Microsoft.CognitiveServicesMultiService" target="_blank" rel="noreferrer">Translator</a> 资源</li><li>进入资源 → &quot;密钥和终结点&quot;</li><li>复制 API Key 和 Region</li></ol><h3 id="deeplx" tabindex="-1">DeepLX <a class="header-anchor" href="#deeplx" aria-label="Permalink to &quot;DeepLX&quot;">​</a></h3><ol><li>访问 <a href="https://github.com/DeepLX/DeepLX" target="_blank" rel="noreferrer">DeepLX GitHub</a></li><li>按照说明本地部署服务</li><li>默认地址：<code>http://127.0.0.1:1188</code></li><li>无需额外配置</li></ol><h2 id="切换方式" tabindex="-1">切换方式 <a class="header-anchor" href="#切换方式" aria-label="Permalink to &quot;切换方式&quot;">​</a></h2><h3 id="快捷键" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键" aria-label="Permalink to &quot;快捷键&quot;">​</a></h3><p>按 <code>Alt+Shift+S</code> 快速切换翻译服务。</p><h3 id="命令面板" tabindex="-1">命令面板 <a class="header-anchor" href="#命令面板" aria-label="Permalink to &quot;命令面板&quot;">​</a></h3><ol><li>按 <code>Ctrl+Shift+P</code></li><li>输入 &quot;切换翻译服务&quot;</li><li>选择要使用的服务</li></ol><h2 id="服务特点" tabindex="-1">服务特点 <a class="header-anchor" href="#服务特点" aria-label="Permalink to &quot;服务特点&quot;">​</a></h2><h3 id="vs-code-copilot" tabindex="-1">VS Code Copilot <a class="header-anchor" href="#vs-code-copilot" aria-label="Permalink to &quot;VS Code Copilot&quot;">​</a></h3><ul><li><strong>优点</strong>：零配置，翻译质量高</li><li><strong>缺点</strong>：需要 Copilot 订阅</li><li><strong>推荐</strong>：首选服务</li></ul><h3 id="谷歌翻译" tabindex="-1">谷歌翻译 <a class="header-anchor" href="#谷歌翻译" aria-label="Permalink to &quot;谷歌翻译&quot;">​</a></h3><ul><li><strong>优点</strong>：免费，无需配置</li><li><strong>缺点</strong>：有调用限制</li><li><strong>推荐</strong>：备用服务</li></ul><h3 id="openai-1" tabindex="-1">OpenAI <a class="header-anchor" href="#openai-1" aria-label="Permalink to &quot;OpenAI&quot;">​</a></h3><ul><li><strong>优点</strong>：翻译质量高</li><li><strong>缺点</strong>：需要 API Key，按量付费</li><li><strong>推荐</strong>：需要高质量翻译时使用</li></ul><h3 id="百度翻译-1" tabindex="-1">百度翻译 <a class="header-anchor" href="#百度翻译-1" aria-label="Permalink to &quot;百度翻译&quot;">​</a></h3><ul><li><strong>优点</strong>：国内服务，速度快</li><li><strong>缺点</strong>：需要注册账号</li><li><strong>推荐</strong>：国内用户推荐</li></ul><h3 id="腾讯翻译君-1" tabindex="-1">腾讯翻译君 <a class="header-anchor" href="#腾讯翻译君-1" aria-label="Permalink to &quot;腾讯翻译君&quot;">​</a></h3><ul><li><strong>优点</strong>：国内服务，速度快</li><li><strong>缺点</strong>：需要腾讯云账号</li><li><strong>推荐</strong>：国内用户推荐</li></ul><h2 id="服务降级" tabindex="-1">服务降级 <a class="header-anchor" href="#服务降级" aria-label="Permalink to &quot;服务降级&quot;">​</a></h2><p>当翻译服务调用失败时，插件会自动按优先级降级：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前服务失败 → 降级到下一个服务 → 所有服务失败 → 降级为拼音</span></span></code></pre></div><h2 id="自动语言检测" tabindex="-1">自动语言检测 <a class="header-anchor" href="#自动语言检测" aria-label="Permalink to &quot;自动语言检测&quot;">​</a></h2><p>所有翻译服务均支持自动语言检测，可翻译以下语言：</p><ul><li>中文</li><li>日文</li><li>韩文</li><li>俄文</li><li>其他非英文字符</li></ul>',36)])])}const b=e(i,[["render",o]]);export{p as __pageData,b as default};
